FROM jsonb_to_recordset('[{"id": "cap-113-society-043", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "表(六)為臺灣某時期四個主要港口，每十年的輸出額總和。根據表中資料，下\n列何者的推論最恰當？\n表(六)                 單位：十萬元\n年分 1896-1905 年   1906-1915 年   1916-1925 年   1926-1935 年\n港口   對外國 對日本 對外國 對日本 對外國 對日本 對外國 對日本\n基隆港     90     312   506 1,215 2,112 5,578 2,321 9,260\n淡水港    708       5   563       7   467     0.5   157     0.2\n安平港    144     135    49     259    25      67    16      65\n打狗港     25     176    45 2,375     831 8,912     479 13,440", "options": ["打狗港的輸出額變化，可能受到殖民母國對糖業的資本挹注影響", "由於基隆離日本較近，其港口對殖民母國的輸出額占比較南部多", "表中各港口占臺灣對外輸出額比重，與十八世紀後期的情況相仿", "表中各港口輸出額的變動，應與當時的統治者推動十大建設有關"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 43, "raw_text": "43. 表(六)為臺灣某時期四個主要港口，每十年的輸出額總和。根據表中資料，下\n    列何者的推論最恰當？\n                              表(六)                 單位：十萬元\n      年分 1896-1905 年   1906-1915 年   1916-1925 年   1926-1935 年\n    港口   對外國 對日本 對外國 對日本 對外國 對日本 對外國 對日本\n    基隆港     90     312   506 1,215 2,112 5,578 2,321 9,260\n    淡水港    708       5   563       7   467     0.5   157     0.2\n    安平港    144     135    49     259    25      67    16      65\n    打狗港     25     176    45 2,375     831 8,912     479 13,440\n   (A)打狗港的輸出額變化，可能受到殖民母國對糖業的資本挹注影響\n   (B)由於基隆離日本較近，其港口對殖民母國的輸出額占比較南部多\n   (C)表中各港口占臺灣對外輸出額比重，與十八世紀後期的情況相仿\n   (D)表中各港口輸出額的變動，應與當時的統治者推動十大建設有關\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-044", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "文中巫童悲劇的發生，主要反映出下列何種現象？", "options": ["文化的差異形成文化位階", "法律的強制力高於宗教信仰", "民眾行為會受到社會規範影響", "公共意見是經由反覆辯論而形成"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": 1.0, "original_question_number": 44, "raw_text": "44. 文中巫童悲劇的發生，主要反映出下列何種現象？\n    (A)文化的差異形成文化位階   (B)法律的強制力高於宗教信仰\n    (C)民眾行為會受到社會規範影響 (D)公共意見是經由反覆辯論而形成\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-045", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "文中關於巫童所受待遇的描述，最能凸顯下列何者的重要性？", "options": ["基本人權應受到普遍性的保障", "公權力的行使應受到法律約束", "自由信仰宗教的權利應受法律保障", "政府的權力應相互制衡以避免濫權 閱讀下列選文，回答第 46 至 48 題： 過去《道路交通管理處罰條例》中的「電動自行車」，僅以電力驅動行 駛，因與電動機車的使用差異不大，且不須懸掛車牌、不須駕照、駕駛者無年 齡限制、價格較低廉，部分民眾喜愛以它作為代步工具，卻也衍生諸多問題。 2022年4月時，政府修正《道路交通管理處罰條例》，將「電動自行車」更 名為「微型電動二輪車」，加入應領用並懸掛車牌進行管理、投保強制汽車責 任保險、年滿14歲才能駕駛等規定，違規者將遭主管機關開罰，並於5月4日由 總統公布。此外，若在修正規定施行前就已持有微型電動二輪車的車主，須在 施行後的二年內領用並懸掛車牌，逾期亦將受罰。 由於法規修正後，仍有諸多行政工作需要時間準備，因此政府宣布這些修 正規定在2022年11月30日才正式施行。"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": 1.0, "original_question_number": 45, "raw_text": "45. 文中關於巫童所受待遇的描述，最能凸顯下列何者的重要性？\n    (A)基本人權應受到普遍性的保障   (B)公權力的行使應受到法律約束\n    (C)自由信仰宗教的權利應受法律保障 (D)政府的權力應相互制衡以避免濫權\n\n閱讀下列選文，回答第 46 至 48 題：\n\n  過去《道路交通管理處罰條例》中的「電動自行車」，僅以電力驅動行\n駛，因與電動機車的使用差異不大，且不須懸掛車牌、不須駕照、駕駛者無年\n齡限制、價格較低廉，部分民眾喜愛以它作為代步工具，卻也衍生諸多問題。\n  2022年4月時，政府修正《道路交通管理處罰條例》，將「電動自行車」更\n名為「微型電動二輪車」，加入應領用並懸掛車牌進行管理、投保強制汽車責\n任保險、年滿14歲才能駕駛等規定，違規者將遭主管機關開罰，並於5月4日由\n總統公布。此外，若在修正規定施行前就已持有微型電動二輪車的車主，須在\n施行後的二年內領用並懸掛車牌，逾期亦將受罰。\n  由於法規修正後，仍有諸多行政工作需要時間準備，因此政府宣布這些修\n正規定在2022年11月30日才正式施行。\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-046", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "根據文中第一段內容判斷，相較於電動機車，部分民眾喜愛使用電動自行車\n的原因，最可能為下列何者？", "options": ["該產品的市場競爭程度日漸提升", "選擇使用該項產品的機會成本較低", "受匯率變化影響，產品販售價格調降", "負向誘因增加，民眾使用產品意願提高"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": 1.0, "original_question_number": 46, "raw_text": "46. 根據文中第一段內容判斷，相較於電動機車，部分民眾喜愛使用電動自行車\n    的原因，最可能為下列何者？\n    (A)該產品的市場競爭程度日漸提升\n    (B)選擇使用該項產品的機會成本較低\n    (C)受匯率變化影響，產品販售價格調降\n    (D)負向誘因增加，民眾使用產品意願提高\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-047", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "文中政府於2022年4月所做的變革，其過程須經下列哪一程序？", "options": ["公民投票複決", "憲法法庭審理", "行政機關移請覆議", "中央立法機關通過"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": 1.0, "original_question_number": 47, "raw_text": "47. 文中政府於2022年4月所做的變革，其過程須經下列哪一程序？\n    (A)公民投票複決\n    (B)憲法法庭審理\n    (C)行政機關移請覆議\n    (D)中央立法機關通過\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-048", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "根據文中內容判斷，在修正規定施行前已持有微型電動二輪車者，關於其領\n用車牌的敘述，下列何者最適當？", "options": ["最晚要在2024年5月3日領用車牌，以免遭受行政處罰", "最晚要在2024年5月3日領用車牌，以免遭受刑事處罰", "最晚要在2024年11月29日領用車牌，以免遭受行政處罰", "最晚要在2024年11月29日領用車牌，以免遭受刑事處罰 閱讀下列選文，回答第 49 至 51 題： 根據《美國憲法》，眾議院的435席議員席次是按照各州人口數分配，而每 10年會依據人口普查結果重新分配席次，且每個州至少有1個席次。圖(二十三) 為不同年分各州眾議員席次的變化情形，每位眾議員平均代表的美國公民也從 646,952人變成761,169人。其中，僅有1席的州為圖中標示斜線的區域，而席次 最多的州皆為加州，在2020年為52席。臺灣現行的區域立委席次分配也採類似 美國的方式，例如73位區域立委中，臺北市應選出8人，雲林縣應選出2人。 圖(二十三)"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 48, "raw_text": "48. 根據文中內容判斷，在修正規定施行前已持有微型電動二輪車者，關於其領\n    用車牌的敘述，下列何者最適當？\n    (A)最晚要在2024年5月3日領用車牌，以免遭受行政處罰\n    (B)最晚要在2024年5月3日領用車牌，以免遭受刑事處罰\n    (C)最晚要在2024年11月29日領用車牌，以免遭受行政處罰\n    (D)最晚要在2024年11月29日領用車牌，以免遭受刑事處罰\n\n\n\n閱讀下列選文，回答第 49 至 51 題：\n    根據《美國憲法》，眾議院的435席議員席次是按照各州人口數分配，而每\n10年會依據人口普查結果重新分配席次，且每個州至少有1個席次。圖(二十三)\n為不同年分各州眾議員席次的變化情形，每位眾議員平均代表的美國公民也從\n646,952人變成761,169人。其中，僅有1席的州為圖中標示斜線的區域，而席次\n最多的州皆為加州，在2020年為52席。臺灣現行的區域立委席次分配也採類似\n美國的方式，例如73位區域立委中，臺北市應選出8人，雲林縣應選出2人。\n\n\n\n\n                    圖(二十三)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-049", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "根據上文及觀察圖(二十三)中不同年分各州眾議員席次的變化情形，可以推論\n美國人口在這段期間有下列何項變動？", "options": ["南部州人口成長速度較東北部的州快", "美國各州持續呈現人口負成長的狀態", "加州因國際移民眾多而人口成長加快", "禁止移民的政策主導德州人口的變化"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 49, "raw_text": "49. 根據上文及觀察圖(二十三)中不同年分各州眾議員席次的變化情形，可以推論\n    美國人口在這段期間有下列何項變動？\n    (A)南部州人口成長速度較東北部的州快\n    (B)美國各州持續呈現人口負成長的狀態\n    (C)加州因國際移民眾多而人口成長加快\n    (D)禁止移民的政策主導德州人口的變化\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-050", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "影響美國各州人口多寡的因素眾多且不相同，觀察圖(二十三)中2020年眾議院\n席次僅有1席的州，下列何者與這些州人口少的原因較無關聯？", "options": ["地形崎嶇", "工業就業機會少", "位居高緯且氣候嚴寒", "深受殖民地式經濟影響"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 50, "raw_text": "50. 影響美國各州人口多寡的因素眾多且不相同，觀察圖(二十三)中2020年眾議院\n    席次僅有1席的州，下列何者與這些州人口少的原因較無關聯？\n    (A)地形崎嶇\n    (B)工業就業機會少\n    (C)位居高緯且氣候嚴寒\n    (D)深受殖民地式經濟影響\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-051", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "根據上文並參考圖(二十四)臺灣人口分布狀況，下\n列關於各行政區立委席次分配的說明何者正確？", "options": ["屏東縣區域立委席次少於臺東縣", "新北市區域立委席次多於宜蘭縣", "彰化縣區域立委席次為全臺最少", "臺南市區域立委席次為全臺最多 㪍涜圦䟸 \u0014\u0013\u0013\u0013ᵸ 圖(二十四) 閱讀下列選文，回答第 52 至 54 題： 1950年代，臺灣電影為配合政府「反共抗俄」政策，政府所屬片廠拍攝的 電影，幾乎都是配合官方意識形態的政治宣傳工具，而民間則出現以歌仔戲劇 本與民俗故事為素材，並用閩南語發音的「臺語電影」。1960年代，因政府強 調社會安定，臺灣電影開啟「健康寫實」風格，主張電影劇情應避免暴露社會 的黑暗面，呈現人性的光輝，受到當時海內外華人市場的歡迎。在1970年代經 濟成長之下，愛情、武俠、功夫、喜劇等電影類型，也進一步走入民眾的休閒 娛樂之中。 1980年代初期，臺灣電影受到香港電影新浪潮的影響，進入「臺灣新電 影」時期。「新電影」發展初期的導演與編劇，在劇本創作上融入鄉土文學的 題材，拍攝風格以強調自然、寫實為主，在題材的選用上，開始有意識的挑戰 官方政治禁忌，而受到相關單位的關切。例如「新電影」初期代表作《兒子的 大玩偶》，在正式上映前，因電影片段中呈現臺北違建林立等有礙政府形象的 畫面，遭官方施壓要求刪減，此事件後來被稱為「削蘋果事件」。最後借助影 視記者楊士琪等人的聲援，才使得電影逃過被刪剪的命運。"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 51, "raw_text": "51. 根據上文並參考圖(二十四)臺灣人口分布狀況，下\n    列關於各行政區立委席次分配的說明何者正確？\n    (A)屏東縣區域立委席次少於臺東縣\n    (B)新北市區域立委席次多於宜蘭縣\n    (C)彰化縣區域立委席次為全臺最少\n    (D)臺南市區域立委席次為全臺最多\n\n                              㪍涜圦䟸\n                              \u0014\u0013\u0013\u0013ᵸ\n                                 圖(二十四)\n\n\n閱讀下列選文，回答第 52 至 54 題：\n  1950年代，臺灣電影為配合政府「反共抗俄」政策，政府所屬片廠拍攝的\n電影，幾乎都是配合官方意識形態的政治宣傳工具，而民間則出現以歌仔戲劇\n本與民俗故事為素材，並用閩南語發音的「臺語電影」。1960年代，因政府強\n調社會安定，臺灣電影開啟「健康寫實」風格，主張電影劇情應避免暴露社會\n的黑暗面，呈現人性的光輝，受到當時海內外華人市場的歡迎。在1970年代經\n濟成長之下，愛情、武俠、功夫、喜劇等電影類型，也進一步走入民眾的休閒\n娛樂之中。\n  1980年代初期，臺灣電影受到香港電影新浪潮的影響，進入「臺灣新電\n影」時期。「新電影」發展初期的導演與編劇，在劇本創作上融入鄉土文學的\n題材，拍攝風格以強調自然、寫實為主，在題材的選用上，開始有意識的挑戰\n官方政治禁忌，而受到相關單位的關切。例如「新電影」初期代表作《兒子的\n大玩偶》，在正式上映前，因電影片段中呈現臺北違建林立等有礙政府形象的\n畫面，遭官方施壓要求刪減，此事件後來被稱為「削蘋果事件」。最後借助影\n視記者楊士琪等人的聲援，才使得電影逃過被刪剪的命運。\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-052", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "根據上文，「新電影」出現之前的戰後臺灣電影，最不可能播映下列何種劇情？", "options": ["中國 明朝年間，來自各路的武功高手在龍門客棧展開激烈戰鬥", "國軍將領對抗日軍時陣亡，蔣中正題字「英烈千秋」表示悼念", "男主角與豪門望族的女兒產生戀情，並捲入家族間的恩怨情仇", "主角因二二八事件遭到軍警處決，留下妻小長期受到政府監視"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": 1.0, "original_question_number": 52, "raw_text": "52. 根據上文，「新電影」出現之前的戰後臺灣電影，最不可能播映下列何種劇情？\n    (A)中國 明朝年間，來自各路的武功高手在龍門客棧展開激烈戰鬥\n    (B)國軍將領對抗日軍時陣亡，蔣中正題字「英烈千秋」表示悼念\n    (C)男主角與豪門望族的女兒產生戀情，並捲入家族間的恩怨情仇\n    (D)主角因二二八事件遭到軍警處決，留下妻小長期受到政府監視\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-053", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "根據上文，「新電影」發展之初，最可能以下列何者作為電影題材？", "options": ["宣揚政府推行南進政策所帶來的經濟成就", "關注一般農民、勞工等小人物生活中的困頓", "受到美援影響，將美國流行文化作為劇情主軸", "重視原住民文化，發揚原住民族音樂與神話傳說"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": 1.0, "original_question_number": 53, "raw_text": "53. 根據上文，「新電影」發展之初，最可能以下列何者作為電影題材？\n    (A)宣揚政府推行南進政策所帶來的經濟成就\n    (B)關注一般農民、勞工等小人物生活中的困頓\n    (C)受到美援影響，將美國流行文化作為劇情主軸\n    (D)重視原住民文化，發揚原住民族音樂與神話傳說\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-113-society-054", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-113-society", "question_type": "single_choice", "question_text": "上文「削蘋果事件」中，國家企圖限制的人民權利類型，與下列何者最相似？", "options": ["對法庭上的被告宣告褫奪公權", "剝奪貪污罪犯應考公職的資格", "禁止過度血腥暴力影像的出版", "要求外國旅客入境應接受審查"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:41+00:00", "source_pdf_sha1": "393a484362c4", "answer_pdf_sha1": "b5ad08c86f8b", "flags": [], "parse_confidence": 1.0, "original_question_number": 54, "raw_text": "54. 上文「削蘋果事件」中，國家企圖限制的人民權利類型，與下列何者最相似？\n    (A)對法庭上的被告宣告褫奪公權\n    (B)剝奪貪污罪犯應考公職的資格\n    (C)禁止過度血腥暴力影像的出版\n    (D)要求外國旅客入境應接受審查\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
